// Parse uploaded JSON file from n8n binary storage (filesystem-v2 compatible)

const binary = $input.item.binary?.file;
if (!binary) {
  throw new Error('No file uploaded under field name "file"');
}

const buf = await this.helpers.getBinaryDataBuffer(0, 'file');
const jsonString = buf.toString('utf8').trim();

let parsed;
try {
  parsed = JSON.parse(jsonString);
} catch (error) {
  const preview = jsonString.slice(0, 200);
  throw new Error(`Uploaded file is not valid JSON. First 200 chars: ${JSON.stringify(preview)}`);
}

// If JSON is an array, wrap into object using the key your chunker expects
if (Array.isArray(parsed)) {
  parsed = { segments: parsed };
}

// Parse speaker map from form body (arrives as a JSON string)
const rawMap = $input.first().json.body?.speaker_map;
if (rawMap) {
  parsed._speakerMap = typeof rawMap === 'string' ? JSON.parse(rawMap) : rawMap;
}

return [{ json: parsed }];

// n8n Code node: Chunk Whisper JSON transcript into time windows
// Input: items[0].json has { duration, segments: [{start,end,text,speaker,words?}, ...] }
// Output: one item per chunk with chunkText suitable for LLM processing.

function pad2(n) {
  return String(n).padStart(2, "0");
}

function secToHms(sec) {
  const s = Math.max(0, Math.floor(sec));
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const ss = s % 60;
  return `${pad2(h)}:${pad2(m)}:${pad2(ss)}`;
}

function normalizeWhitespace(str) {
  return String(str ?? "")
    .replace(/\s+/g, " ")
    .trim();
}

/**
 * Apply spelling/name corrections.
 * corrections is an object like: { "Keth": "Kaeth", "Thaylen": "Thaylenah" }
 * This does simple global replacement with word boundaries where possible.
 */
function applyCorrections(text, corrections) {
  let out = text;
  for (const [from, to] of Object.entries(corrections || {})) {
    if (!from) continue;

    // If "from" looks like a single word, use word boundaries.
    // Otherwise do a plain global replace.
    const isSingleWord = /^[A-Za-z0-9_'-]+$/.test(from);
    if (isSingleWord) {
      const re = new RegExp(`\\b${from.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "g");
      out = out.replace(re, to);
    } else {
      const re = new RegExp(from.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"), "g");
      out = out.replace(re, to);
    }
  }
  return out;
}

function buildLine(seg, corrections, speakerMap) {
  const ts = secToHms(seg.start);
  const rawSpeaker = seg.speaker ?? "UNKNOWN";
  const speaker = speakerMap[rawSpeaker] ?? rawSpeaker;
  const text = applyCorrections(normalizeWhitespace(seg.text), corrections);
  if (!text) return null;
  return `[${ts}] ${speaker}: ${text}`;
}

// --- Configuration you can tweak in the node UI via item.json settings ---
// If you want configurable settings, you can set these upstream in a Set node:
// items[0].json._chunkMinutes, items[0].json._overlapSeconds, items[0].json._includeSegments, items[0].json._corrections

const input = items[0].json;
const speakerMap = input._speakerMap ?? {};

// Default to 10 minute chunks for long sessions, works well for 3 hour audio
const chunkMinutes = Number(input._chunkMinutes ?? 10);
const chunkSizeSec = Math.max(60, Math.floor(chunkMinutes * 60));

// Optional overlap (helps with boundary context). Usually 0 is fine for fact extraction.
const overlapSec = Number(input._overlapSeconds ?? 0);

// Include lightweight segments array in output (for debugging). Set false to reduce payload.
const includeSegments = Boolean(input._includeSegments ?? false);

// Corrections map: set input._corrections = { "Keth": "Kaeth", ... } upstream if desired
const corrections = input._corrections ?? {};
const contextDump = input.contextDump ?? "";

// Validate
if (!input || !Array.isArray(input.segments)) {
  throw new Error("Expected items[0].json.segments to be an array");
}

// 1) Normalize and sort segments by start time
const segments = input.segments
  .map((s) => ({
    start: Number(s.start),
    end: Number(s.end),
    speaker: s.speaker ?? "UNKNOWN",
    text: s.text ?? "",
    // Intentionally ignore s.words to keep memory small
  }))
  .filter((s) => Number.isFinite(s.start) && Number.isFinite(s.end))
  .sort((a, b) => a.start - b.start);

// 2) Determine duration
const durationSec =
  Number.isFinite(Number(input.duration)) ? Number(input.duration) :
  (segments.length ? Math.max(...segments.map((s) => s.end)) : 0);

// 3) Build chunk windows [0..duration) stepping by chunkSizeSec
const outputs = [];
let chunkIndex = 0;

for (let windowStart = 0; windowStart < durationSec + 0.0001; windowStart += chunkSizeSec) {
  const windowEnd = Math.min(durationSec, windowStart + chunkSizeSec);

  // Select segments whose start is within the window
  const windowSegs = segments.filter((s) => s.start >= windowStart && s.start < windowEnd);

  if (windowSegs.length === 0) {
    // Skip empty windows
    continue;
  }

  // Optional overlap: add a little context before/after by including segments that start in overlap region
  let finalSegs = windowSegs;
  if (overlapSec > 0) {
    const overlapStart = Math.max(0, windowStart - overlapSec);
    const overlapEnd = Math.min(durationSec, windowEnd + overlapSec);
    finalSegs = segments.filter((s) => s.start >= overlapStart && s.start < overlapEnd);
  }

  // Build compact chunk text
  const lines = [];
  for (const seg of finalSegs) {
    const line = buildLine(seg, corrections, speakerMap);
    if (line) lines.push(line.trim());
  }

  // Small optimization: if crosstalk causes identical lines due to duplication, remove exact dupes
  const dedupedLines = [...new Set(lines.map(l => l.trim()))];

  chunkIndex += 1;

  const out = {
    chunkIndex,
    rangeStartSec: windowStart,
    rangeEndSec: windowEnd,
    rangeStart: secToHms(windowStart),
    rangeEnd: secToHms(windowEnd),
    chunkText: dedupedLines.join("\n"),
    contextDump
  };

  if (includeSegments) {
    out.segments = finalSegs.map((s) => ({
      start: s.start,
      end: s.end,
      speaker: s.speaker,
      text: applyCorrections(normalizeWhitespace(s.text), corrections),
    }));
  }

  outputs.push({ json: out });
}

return outputs;

