function normalize(str) {
  return String(str || "")
    .trim()
    .toLowerCase()
    .replace(/[.,!?;:]/g, "")
    .replace(/\s+/g, " ");
}

function sortByRange(items) {
  return [...items].sort((a, b) => {
    const aStart = a._rangeStartSec ?? 0;
    const bStart = b._rangeStartSec ?? 0;
    return aStart - bStart;
  });
}

function dedupeTextArray(items) {
  const seen = new Set();
  const result = [];

  for (const entry of items) {
    if (!entry?.text) continue;

    const key = normalize(entry.text);
    if (!seen.has(key)) {
      seen.add(key);
      result.push({ text: entry.text.trim() });
    }
  }

  return result;
}

function mergeNamedObjects(items) {
  const map = new Map();

  for (const entry of items) {
    if (!entry?.name) continue;

    const key = normalize(entry.name);
    const noteText = entry.notes?.trim();

    if (!map.has(key)) {
      map.set(key, {
        name: entry.name.trim(),
        notes: noteText ? [noteText] : []
      });
    } else {
      const existing = map.get(key);

      if (noteText) {
        const alreadyExists = existing.notes.some(
          n => normalize(n) === normalize(noteText)
        );

        if (!alreadyExists) {
          existing.notes.push(noteText);
        }
      }
    }
  }

  return Array.from(map.values());
}

function crossCategoryDedupe(primary, secondary) {
  const secondarySet = new Set(
    secondary
      .filter(e => e?.text)
      .map(e => normalize(e.text))
  );

  return primary.filter(e => e?.text && !secondarySet.has(normalize(e.text)));
}

const aggregated = {
  events: [],
  locations: [],
  npcs: [],
  info_learned: [],
  combat: [],
  decisions: [],
  character_moments: [],
  loose_threads: [],
  inventory_rewards: []
};

// --- Collect everything with range tracking ---
for (const item of items) {
  const wrapper = item.json ?? {};

  // Some nodes output { output: {...} }, some output {...}.
  // Sometimes output can be a string if parsing failed, so guard it.
  const maybeOutput = wrapper.output;
  const data =
    (maybeOutput && typeof maybeOutput === "object" && !Array.isArray(maybeOutput))
      ? maybeOutput
      : wrapper;

  const rangeStartSec = wrapper.rangeStartSec ?? data.rangeStartSec ?? 0;
  let rangeStart = wrapper.rangeStart ?? data.rangeStart ?? null;
  let rangeEnd = wrapper.rangeEnd ?? data.rangeEnd ?? null;

  if ((!rangeStart || !rangeEnd) && typeof data.range === "string") {
    const m = data.range.match(/^(\d{2}:\d{2}:\d{2})\s*[–-]\s*(\d{2}:\d{2}:\d{2})$/);
    if (m) {
      rangeStart = rangeStart ?? m[1];
      rangeEnd = rangeEnd ?? m[2];
    }
  }

  for (const key of Object.keys(aggregated)) {
    const arr = data[key];
    if (!Array.isArray(arr)) continue;

    for (const entry of arr) {
      // entry should be an object; skip bad entries safely
      if (!entry || typeof entry !== "object") continue;

      aggregated[key].push({
        ...entry,
        _rangeStartSec: rangeStartSec,
        _rangeStart: rangeStart,
        _rangeEnd: rangeEnd
      });
    }
  }
}

// --- Chronological ordering ---
for (const key of Object.keys(aggregated)) {
  aggregated[key] = sortByRange(aggregated[key]);
}

// --- Deduplicate text-based categories ---
aggregated.events = dedupeTextArray(aggregated.events);
aggregated.info_learned = dedupeTextArray(aggregated.info_learned);
aggregated.combat = dedupeTextArray(aggregated.combat);
aggregated.decisions = dedupeTextArray(aggregated.decisions);
aggregated.character_moments = dedupeTextArray(aggregated.character_moments);
aggregated.loose_threads = dedupeTextArray(aggregated.loose_threads);
aggregated.inventory_rewards = dedupeTextArray(aggregated.inventory_rewards);

// --- Cross-category dedupe (prevent same line appearing twice) ---
aggregated.decisions = crossCategoryDedupe(
  aggregated.decisions,
  aggregated.events
);

aggregated.combat = crossCategoryDedupe(
  aggregated.combat,
  aggregated.events
);

// --- Merge named entities ---
aggregated.npcs = mergeNamedObjects(aggregated.npcs);
aggregated.locations = mergeNamedObjects(aggregated.locations);

return [
  {
    json: {
      allFacts: aggregated,
      contextDump: items[0]?.json?.contextDump ?? ""
    }
  }
];
